// Load project configuration from file
const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/.n8n/config.json', 'utf8'));
return [{ json: config }];

// Check if tonight there's a Kodesh entry (candle lighting)
// Also determines if this is a Chol→Kodesh transition or Kodesh→Kodesh (multi-day)
const config = $('Load Config').first().json;
const LAT = config.settings.LATITUDE;
const LON = config.settings.LONGITUDE;

const today = new Date();
const dateStr = today.toISOString().slice(0, 10);
const yesterday = new Date(today.getTime() - 24 * 60 * 60 * 1000);
const yesterdayStr = yesterday.toISOString().slice(0, 10);

// Get Hebcal shabbat data
const url = `https://www.hebcal.com/shabbat?cfg=json&latitude=${LAT}&longitude=${LON}&M=on&b=18`;
const response = await this.helpers.httpRequest({ method: 'GET', url, json: true });

let candleLighting = null;
let havdalah = null;
let isErevKodesh = false;
let holidayName = '';

for (const item of response.items || []) {
  const itemDate = item.date ? item.date.slice(0, 10) : '';
  if (item.category === 'candles' && itemDate === dateStr) {
    candleLighting = item.date;
    isErevKodesh = true;
    holidayName = item.title || 'Shabbat';
  }
  if (item.category === 'havdalah') {
    havdalah = item.date;
  }
}

// Determine if today is already Kodesh (yesterday had candle lighting or today is Shabbat morning)
// If today is already Kodesh, then tonight's candle lighting is Kodesh→Kodesh (no shutdown needed)
let isTodayAlreadyKodesh = false;

// Check if yesterday was erev (had candle lighting)
for (const item of response.items || []) {
  const itemDate = item.date ? item.date.slice(0, 10) : '';
  if (item.category === 'candles' && itemDate === yesterdayStr) {
    isTodayAlreadyKodesh = true;
  }
}

// Also check: if today is Saturday (woke up on Shabbat) 
if (today.getDay() === 6) {
  isTodayAlreadyKodesh = true;
}

// Check Hebrew calendar for Yom Tov today
const calUrl = `https://www.hebcal.com/hebcal?v=1&cfg=json&year=now&month=now&maj=on&min=off&mod=off&nx=off&ss=off&mf=off&c=off&geo=pos&latitude=${LAT}&longitude=${LON}`;
const calResp = await this.helpers.httpRequest({ method: 'GET', url: calUrl, json: true });

for (const item of calResp.items || []) {
  const itemDate = item.date ? item.date.slice(0, 10) : '';
  if (itemDate === dateStr && item.yomtov === true) {
    isTodayAlreadyKodesh = true;
  }
}

// KEY LOGIC:
// isTransitionCholToKodesh = there IS candle lighting tonight AND today is NOT already Kodesh
const isTransitionCholToKodesh = isErevKodesh && !isTodayAlreadyKodesh;

// Sunset time (candle lighting + 18 min ≈ sunset)
let sunsetTime = null;
if (candleLighting) {
  const cl = new Date(candleLighting);
  sunsetTime = new Date(cl.getTime() + 18 * 60 * 1000).toISOString();
}

const month = today.getMonth() + 1;
const isSummerMonth = config.settings.SUMMER_MONTHS.includes(month);

return [{
  json: {
    isErevKodesh,
    isTransitionCholToKodesh,
    isTodayAlreadyKodesh,
    candleLighting,
    havdalah,
    sunsetTime,
    holidayName,
    isSummerMonth,
    month,
    dateStr
  }
}];

// Get weather forecast for the next 36 hours from Tomorrow.io
const config = $('Load Config').first().json;
const LAT = config.settings.LATITUDE;
const LON = config.settings.LONGITUDE;
const API_KEY = config.secrets.TOMORROW_IO_KEY;

const url = `https://api.tomorrow.io/v4/weather/forecast?location=${LAT},${LON}&timesteps=1h&apikey=${API_KEY}`;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  json: true
});

// Extract relevant hourly data for the next 36 hours
const hourly = (response.timelines?.hourly || []).slice(0, 36).map(h => ({
  time: h.time,
  temperature: h.values?.temperature,
  humidity: h.values?.humidity,
  cloudCover: h.values?.cloudCover,
  weatherCode: h.values?.weatherCode
}));

// Calculate max temperature for today/tomorrow
const maxTemp = Math.max(...hourly.map(h => h.temperature || 0));

return [{
  json: {
    forecast: hourly,
    maxTemp,
    currentTemp: hourly[0]?.temperature || null
  }
}];

// Plan Erev Shabbat actions: shutdown devices + schedule AC for Friday night
const config = $('Load Config').first().json;
const shabbatData = $('Check Shabbat Entry').first().json;
const weatherData = $('Get Weather Forecast').first().json;

const candleLighting = shabbatData.candleLighting;
const sunsetTime = shabbatData.sunsetTime;
const isSummer = shabbatData.isSummerMonth;
const maxTemp = weatherData.maxTemp;

const devices = config.devices;
const schedule = [];

// === FIXED ACTIONS: Always on Erev Shabbat ===

// 1. Turn OFF Boiler 30 min before candle lighting
const clDate = new Date(candleLighting);
const boilerOff = new Date(clDate.getTime() - 30 * 60 * 1000);
schedule.push({
  time: boilerOff.toISOString(),
  deviceId: devices.BOILER,
  entity: 'Boiler',
  action: 'OFF',
  commands: [{ code: 'switch_1', value: false }]
});

// 2. Turn OFF Mini-Bar at candle lighting
schedule.push({
  time: candleLighting,
  deviceId: devices.MINI_BAR,
  entity: 'Mini-Bar',
  action: 'OFF',
  commands: [{ code: 'switch_1', value: false }]
});

// === CONDITIONAL: AC for Friday night dinner (summer + hot) ===
if (isSummer && maxTemp >= config.settings.AC_TEMP_THRESHOLD) {
  // Living room ACs: 1 hour after sunset for 2 hours
  const sunsetDate = new Date(sunsetTime);
  const acOn = new Date(sunsetDate.getTime() + 60 * 60 * 1000);
  const acOff = new Date(acOn.getTime() + 2 * 60 * 60 * 1000);

  // Turn ON living room ACs
  schedule.push({
    time: acOn.toISOString(),
    deviceId: devices.AC_LIVING_1,
    entity: 'AC Living 1',
    action: 'ON',
    commands: [{ code: 'switch', value: true }, { code: 'mode', value: 'cold' }, { code: 'temp_set', value: 24 }]
  });
  schedule.push({
    time: acOn.toISOString(),
    deviceId: devices.AC_LIVING_2,
    entity: 'AC Living 2',
    action: 'ON',
    commands: [{ code: 'switch', value: true }, { code: 'mode', value: 'cold' }, { code: 'temp_set', value: 24 }]
  });

  // Turn OFF living room ACs after dinner
  schedule.push({
    time: acOff.toISOString(),
    deviceId: devices.AC_LIVING_1,
    entity: 'AC Living 1',
    action: 'OFF',
    commands: [{ code: 'switch', value: false }]
  });
  schedule.push({
    time: acOff.toISOString(),
    deviceId: devices.AC_LIVING_2,
    entity: 'AC Living 2',
    action: 'OFF',
    commands: [{ code: 'switch', value: false }]
  });

  // Bedroom AC: after dinner until 11:00 next morning
  schedule.push({
    time: acOff.toISOString(),
    deviceId: devices.AC_BEDROOM,
    entity: 'AC Bedroom',
    action: 'ON',
    commands: [{ code: 'switch', value: true }, { code: 'mode', value: 'cold' }, { code: 'temp_set', value: 24 }]
  });

  // Kids AC: after dinner until 11:00 next morning
  schedule.push({
    time: acOff.toISOString(),
    deviceId: devices.AC_KIDS,
    entity: 'AC Kids',
    action: 'ON',
    commands: [{ code: 'switch', value: true }, { code: 'mode', value: 'cold' }, { code: 'temp_set', value: 24 }]
  });
}

// Sort by time
schedule.sort((a, b) => new Date(a.time) - new Date(b.time));

return [{ json: { schedule, summary: `Erev Shabbat plan: ${schedule.length} actions scheduled` } }];

// Execute scheduled Tuya commands at the right times
// This node receives a schedule array and executes commands that are due NOW
const crypto = require('crypto');
const config = $('Load Config').first().json;
const scheduleData = $input.first().json;

const TUYA_ACCESS_ID = config.secrets.TUYA_ACCESS_ID;
const TUYA_ACCESS_SECRET = config.secrets.TUYA_ACCESS_SECRET;
const API_URL = 'https://openapi.tuyaeu.com';

// Get Tuya token
async function getTuyaToken() {
  const timestamp = Date.now().toString();
  const path = '/v1.0/token?grant_type=1';
  const contentHash = crypto.createHash('sha256').update('').digest('hex');
  const stringToSign = 'GET\n' + contentHash + '\n\n' + path;
  const str = TUYA_ACCESS_ID + timestamp + stringToSign;
  const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: API_URL + path,
    headers: { 't': timestamp, 'sign': sign, 'client_id': TUYA_ACCESS_ID, 'sign_method': 'HMAC-SHA256' },
    json: true
  });

  return response.result.access_token;
}

// Send command to device
async function sendCommand(token, deviceId, commands) {
  const timestamp = Date.now().toString();
  const path = '/v1.0/devices/' + deviceId + '/commands';
  const body = JSON.stringify({ commands });

  const contentHash = crypto.createHash('sha256').update(body).digest('hex');
  const stringToSign = 'POST\n' + contentHash + '\n\n' + path;
  const str = TUYA_ACCESS_ID + token + timestamp + stringToSign;
  const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: API_URL + path,
    headers: {
      't': timestamp, 'sign': sign, 'client_id': TUYA_ACCESS_ID,
      'sign_method': 'HMAC-SHA256', 'access_token': token,
      'Content-Type': 'application/json'
    },
    body: body,
    json: true
  });

  return response;
}

// Filter actions that should execute NOW (within 2 minute window)
const now = Date.now();
const WINDOW_MS = 2 * 60 * 1000; // 2 minutes

const dueActions = scheduleData.schedule.filter(action => {
  const actionTime = new Date(action.time).getTime();
  return Math.abs(actionTime - now) <= WINDOW_MS;
});

if (dueActions.length === 0) {
  return [{ json: { executed: 0, message: 'No actions due at this time' } }];
}

// Execute due actions
const token = await getTuyaToken.call(this);
const results = [];

for (const action of dueActions) {
  try {
    const result = await sendCommand.call(this, token, action.deviceId, action.commands);
    results.push({
      entity: action.entity,
      action: action.action,
      success: result.success,
      time: action.time
    });
  } catch (e) {
    results.push({
      entity: action.entity,
      action: action.action,
      success: false,
      error: e.message,
      time: action.time
    });
  }
}

return [{ json: { executed: results.length, results } }];
